    }

    case 'write_file': {
      const filePath = input.file_path as string | undefined;
      return `[TOOL: write_file] ${filePath || ''}`;
    }

    default: {
      // 其他 tool 顯示第一個有意義的參數
      const firstValue = Object.values(input).find(
        (v) => typeof v === 'string' && v.length > 0
      ) as string | undefined;
